searchConfig.beforeFetch:
function willFetch(data) {
  data.key = data.key || data.q || "";
  return data;
}

searchConfig.afterFetch:
function didFetch(content) {
  var data = [];
  if (content && content.values) {
    content.values.forEach(function (item) {
      data.push({ value: item.emplId, text: item.name, deptFullPath: item.deptFullPath });
    });
  }
  return data;
}
